// Parse RSS feeds for all 3 topics
function parseRSS(xmlText) {
  const items = [];
  const itemRegex = /<item>([\s\S]*?)<\/item>/g;
  let match;

  while ((match = itemRegex.exec(xmlText)) !== null && items.length < 5) {
    const item = match[1];
    const getTag = (tag) => {
      const m = item.match(new RegExp(`<${tag}[^>]*>(?:<![CDATA[)?([\ s\S]*?)(?:\]\]>)?<\/${tag}>`, 'i'));
      return m ? m[1].trim() : '';
    };

    const title = getTag('title').replace(/<[^>]+>/g, '');
    const source = getTag('source') || getTag('dc:creator') || 'Unknown';
    const date = getTag('pubDate') || getTag('dc:date') || '';
    const description = getTag('description').replace(/<[^>]+>/g, '').slice(0, 150);
    const url = getTag('link') || getTag('guid');

    if (title && url) {
      items.push({ title, source, date, description, url });
    }
  }
  return items;
}

const immersiveXml = $('Fetch Immersive Tech').first().json.data || $('Fetch Immersive Tech').first().json.body || '';
const quantumXml = $('Fetch Quantum Tech').first().json.data || $('Fetch Quantum Tech').first().json.body || '';
const startupXml = $('Fetch Startup News').first().json.data || $('Fetch Startup News').first().json.body || '';

const immersiveArticles = parseRSS(immersiveXml);
const quantumArticles = parseRSS(quantumXml);
const startupArticles = parseRSS(startupXml);

return [{ json: {
  topics: [
    { name: 'immersive technology XR AR VR', channel: 'C0AL15CESF4', articles: immersiveArticles },
    { name: 'quantum computing technology', channel: 'C0ALE2MSHL1', articles: quantumArticles },
    { name: 'startup business strategy funding', channel: 'C0AKUPCPSD9', articles: startupArticles }
  ]
}}];

// Format immersive tech for Slack
const ollamaResp = $input.first().json;
const msgContent = ollamaResp.message?.content || '{}';
let articlesData = [];

try {
  const jsonMatch = msgContent.match(/\[\s*\{[\s\S]*?\}\s*\]/);
  articlesData = jsonMatch ? JSON.parse(jsonMatch[0]) : $('Process All Topics').first().json.topics[0].articles;
} catch (e) {
  articlesData = $('Process All Topics').first().json.topics[0].articles;
}

const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: ':telescope: Immersive Technology', emoji: true }
  },
  { type: 'divider' }
];

articlesData.forEach((article, idx) => {
  blocks.push({
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*<${article.url}|${article.title}>*\n${article.source} • ${article.date}\n_${article.summary || article.description}_`
    }
  });
  if (idx < articlesData.length - 1) blocks.push({ type: 'divider' });
});

return [{ json: { channel: 'C0AL15CESF4', blocks } }];

